#!/bin/sh
# cargo-loco-generate-scaffold/generate.sh
#
# Generator script for Loco scaffolding.
#
# Run from inside a fresh Loco project (one created via
# `loco new --name <form-slug> --db postgres --bg async --assets serverside`)
# to scaffold every CRUD resource for this form. Tables are scaffolded in the
# same order as the form's sql-migrations/ so that FK targets already exist
# when referencing tables are created.
#
# Generated by bin/generate-cargo-loco-scaffold.py from sql-migrations/*.sql.
# Do not edit by hand — re-run the generator after changing the SQL migrations.

set -euf


echo "Scaffolding plastic-surgery-assessment (15 tables)..."

cargo loco generate scaffold patient \
    first_name:string! \
    last_name:string! \
    date_of_birth:date! \
    nhs_number:string^ \
    sex:string! \
    weight_kg:double \
    height_cm:double \
    bmi:double \
    --htmx

cargo loco generate scaffold assessment \
    patient:references \
    status:string! \
    --htmx

cargo loco generate scaffold assessment_demographics \
    assessment:references \
    preferred_name:string! \
    gender_identity:string! \
    ethnicity:string! \
    preferred_language:string! \
    interpreter_required:string! \
    gp_name:string! \
    gp_practice:string! \
    referrer_name:string! \
    referrer_role:string! \
    --htmx

cargo loco generate scaffold assessment_reason_for_referral \
    assessment:references \
    referral_type:string! \
    referral_type_other:text! \
    urgency:string! \
    primary_complaint:text! \
    affected_body_area:string! \
    affected_body_area_other:text! \
    laterality:string! \
    duration_of_condition:string! \
    previous_consultations:string! \
    previous_consultations_details:text! \
    referral_notes:text! \
    --htmx

cargo loco generate scaffold assessment_medical_surgical_history \
    assessment:references \
    previous_plastic_surgery:string! \
    previous_plastic_surgery_details:text! \
    previous_general_surgery:string! \
    previous_general_surgery_details:text! \
    wound_healing_problems:string! \
    wound_healing_details:text! \
    keloid_hypertrophic_scarring:string! \
    scarring_details:text! \
    diabetes:string! \
    diabetes_controlled:string! \
    hypertension:string! \
    cardiac_disease:string! \
    cardiac_disease_details:text! \
    respiratory_disease:string! \
    respiratory_disease_details:text! \
    autoimmune_disease:string! \
    autoimmune_disease_details:text! \
    bleeding_disorder:string! \
    bleeding_disorder_details:text! \
    immunosuppressed:string! \
    immunosuppressed_details:text! \
    cancer_history:string! \
    cancer_history_details:text! \
    medical_history_notes:text! \
    --htmx

cargo loco generate scaffold assessment_current_condition \
    assessment:references \
    condition_category:string! \
    condition_description:text! \
    lesion_size_length_mm:int \
    lesion_size_width_mm:int \
    lesion_size_depth_mm:int \
    tissue_loss:string! \
    tissue_loss_percentage:double \
    functional_impairment:string! \
    functional_impairment_details:text! \
    pain_level:int \
    cosmetic_concern:string! \
    impact_on_daily_activities:string! \
    current_condition_notes:text! \
    --htmx

cargo loco generate scaffold assessment_wound_tissue \
    assessment:references \
    has_open_wound:string! \
    wound_classification:string! \
    wound_age:string! \
    wound_aetiology:string! \
    wound_bed_tissue:string! \
    wound_exudate:string! \
    wound_infection_signs:string! \
    wound_infection_details:text! \
    tissue_viability:string! \
    surrounding_skin:string! \
    vascular_supply:string! \
    sensory_status:string! \
    previous_wound_treatments:text! \
    wound_tissue_notes:text! \
    --htmx

cargo loco generate scaffold assessment_psychological \
    assessment:references \
    body_dysmorphic_concern:string! \
    body_dysmorphic_details:text! \
    realistic_expectations:string! \
    expectations_details:text! \
    motivation:string! \
    motivation_other:text! \
    previous_mental_health:string! \
    mental_health_details:text! \
    anxiety_level:string! \
    depression_screen:string! \
    social_impact:string! \
    social_impact_details:text! \
    psychological_referral_needed:string! \
    psychological_notes:text! \
    --htmx

cargo loco generate scaffold assessment_anaesthetic_risk \
    assessment:references \
    asa_class:string! \
    previous_anaesthetic:string! \
    anaesthetic_complications:string! \
    anaesthetic_complications_details:text! \
    difficult_airway:string! \
    difficult_airway_details:text! \
    malignant_hyperthermia_risk:string! \
    family_anaesthetic_problems:string! \
    family_anaesthetic_details:text! \
    smoking_status:string! \
    pack_years:double \
    alcohol_consumption:string! \
    recreational_drugs:string! \
    recreational_drugs_details:text! \
    obstructive_sleep_apnoea:string! \
    anaesthetic_preference:string! \
    anaesthetic_notes:text! \
    --htmx

cargo loco generate scaffold assessment_photography_documentation \
    assessment:references \
    clinical_photos_taken:string! \
    photo_consent_obtained:string! \
    number_of_photos:int \
    photo_views_taken:text! \
    standardised_views:string! \
    measurements_recorded:string! \
    measurement_details:text! \
    diagrams_drawn:string! \
    diagram_notes:text! \
    previous_imaging:string! \
    previous_imaging_type:string! \
    previous_imaging_findings:text! \
    documentation_notes:text! \
    --htmx

cargo loco generate scaffold assessment_medications_allergies \
    assessment:references \
    on_anticoagulants:string! \
    anticoagulant_details:text! \
    on_antiplatelets:string! \
    antiplatelet_details:text! \
    on_steroids:string! \
    steroid_details:text! \
    on_immunosuppressants:string! \
    immunosuppressant_details:text! \
    on_chemotherapy:string! \
    chemotherapy_details:text! \
    on_hormone_therapy:string! \
    hormone_therapy_details:text! \
    other_medications:text! \
    has_drug_allergies:string! \
    drug_allergy_details:text! \
    latex_allergy:string! \
    adhesive_allergy:string! \
    other_allergies:text! \
    medication_adherence:string! \
    medications_allergies_notes:text! \
    --htmx

cargo loco generate scaffold assessment_procedure_planning \
    assessment:references \
    proposed_procedure:text! \
    procedure_complexity:string! \
    surgical_approach:string! \
    expected_duration_minutes:int \
    expected_hospital_stay:string! \
    flap_type:string! \
    implant_required:string! \
    implant_details:text! \
    vte_risk:string! \
    antibiotic_prophylaxis:string! \
    anticipated_risks:text! \
    alternative_treatments:text! \
    consent_discussion:string! \
    consent_form_signed:string! \
    cooling_off_period_offered:string! \
    follow_up_plan:text! \
    procedure_planning_notes:text! \
    --htmx

cargo loco generate scaffold grading_result \
    assessment:references \
    asa_class:string! \
    wound_class:string! \
    complexity_score:string! \
    overall_risk_level:string! \
    graded_at:ts! \
    --htmx

cargo loco generate scaffold grading_fired_rule \
    grading_result:references \
    rule_id:string! \
    category:string! \
    description:text! \
    severity_level:string! \
    --htmx

cargo loco generate scaffold grading_additional_flag \
    grading_result:references \
    flag_id:string! \
    category:string! \
    message:text! \
    priority:string! \
    --htmx

echo "Done."
